# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.shareintentapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ShareActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        val sharedIntent = intent
        if (sharedIntent.action == Intent.ACTION_SEND) {
            when (sharedIntent.type) {
                "text/plain" -> handleText(sharedIntent.getStringExtra(Intent.EXTRA_TEXT))
                "image/*" -> handleImage(sharedIntent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))
                else -> {
                    // Handle other types of shared content if needed
                }
            }
        }
    }

    private fun handleText(text: String?) {
        val textView = findViewById<TextView>(R.id.sharedTextView)
        textView.text = text
    }

    private fun handleImage(imageUri: Uri?) {
        val imageView = findViewById<ImageView>(R.id.sharedImageView)
        imageView.setImageURI(imageUri)
    }
}